import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as n,d as r}from"./app-0a44add1.js";const i={},t=r('<h2 id="material" tabindex="-1"><a class="header-anchor" href="#material" aria-hidden="true">#</a> Material</h2><p>材质的抽象基类。</p><p>材质描述了对象objects的外观。它们的定义方式与渲染器无关， 因此，如果您决定使用不同的渲染器，不必重写材质。</p><p>所有其他材质类型都继承了以下属性和方法（尽管它们可能具有不同的默认值）。</p><h2 id="构造函数" tabindex="-1"><a class="header-anchor" href="#构造函数" aria-hidden="true">#</a> 构造函数</h2><h3 id="material-1" tabindex="-1"><a class="header-anchor" href="#material-1" aria-hidden="true">#</a> Material()</h3><p>该方法创建一个通用材质。</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2><h3 id="alphatest-float" tabindex="-1"><a class="header-anchor" href="#alphatest-float" aria-hidden="true">#</a> .alphaTest : Float</h3><p>设置运行alphaTest时要使用的alpha值。如果不透明度低于此值，则不会渲染材质。默认值为0。</p><h3 id="alphatocoverage-boolean" tabindex="-1"><a class="header-anchor" href="#alphatocoverage-boolean" aria-hidden="true">#</a> .alphaToCoverage : Boolean</h3><p>启用alpha to coverage. 只能在开启了MSAA的渲染环境中使用 (当渲染器创建的时候antialias 属性要true才能使用). 默认为 false.</p><h3 id="blenddst-integer" tabindex="-1"><a class="header-anchor" href="#blenddst-integer" aria-hidden="true">#</a> .blendDst : Integer</h3><p>混合目标。默认值为OneMinusSrcAlphaFactor。 目标因子所有可能的取值请参阅constants。 必须将材质的blending设置为CustomBlending才能生效。</p><h3 id="blenddstalpha-integer" tabindex="-1"><a class="header-anchor" href="#blenddstalpha-integer" aria-hidden="true">#</a> .blendDstAlpha : Integer</h3><p>.blendDst的透明度。 默认值为 null.</p><h3 id="blendequation-integer" tabindex="-1"><a class="header-anchor" href="#blendequation-integer" aria-hidden="true">#</a> .blendEquation : Integer</h3><p>使用混合时所采用的混合方程式。默认值为AddEquation。 混合方程式所有可能的取值请参阅constants。 必须将材质的blending设置为CustomBlending才能生效。</p><h3 id="blendequationalpha-integer" tabindex="-1"><a class="header-anchor" href="#blendequationalpha-integer" aria-hidden="true">#</a> .blendEquationAlpha : Integer</h3><p>.blendEquation 的透明度. 默认值为 null.</p><h3 id="blending-blending" tabindex="-1"><a class="header-anchor" href="#blending-blending" aria-hidden="true">#</a> .blending : Blending</h3><p>在使用此材质显示对象时要使用何种混合。<br> 必须将其设置为CustomBlending才能使用自定义blendSrc, blendDst 或者 [page:Constant blendEquation]。 混合模式所有可能的取值请参阅constants。默认值为NormalBlending。</p><h3 id="blendsrc-integer" tabindex="-1"><a class="header-anchor" href="#blendsrc-integer" aria-hidden="true">#</a> .blendSrc : Integer</h3><p>混合源。默认值为SrcAlphaFactor。 源因子所有可能的取值请参阅constants。<br> 必须将材质的blending设置为CustomBlending才能生效。</p><h3 id="blendsrcalpha-integer" tabindex="-1"><a class="header-anchor" href="#blendsrcalpha-integer" aria-hidden="true">#</a> .blendSrcAlpha : Integer</h3><p>.blendSrc的透明度。 默认值为 null.</p><h3 id="clipintersection-boolean" tabindex="-1"><a class="header-anchor" href="#clipintersection-boolean" aria-hidden="true">#</a> .clipIntersection : Boolean</h3><p>更改剪裁平面的行为，以便仅剪切其交叉点，而不是它们的并集。默认值为 false。</p><h3 id="clippingplanes-array" tabindex="-1"><a class="header-anchor" href="#clippingplanes-array" aria-hidden="true">#</a> .clippingPlanes : Array</h3><p>用户定义的剪裁平面，在世界空间中指定为THREE.Plane对象。这些平面适用于所有使用此材质的对象。空间中与平面的有符号距离为负的点被剪裁（未渲染）。 这需要WebGLRenderer.localClippingEnabled为true。 示例请参阅WebGL / clipping /intersection。默认值为 null。</p><h3 id="clipshadows-boolean" tabindex="-1"><a class="header-anchor" href="#clipshadows-boolean" aria-hidden="true">#</a> .clipShadows : Boolean</h3><p>定义是否根据此材质上指定的剪裁平面剪切阴影。默认值为 false。</p><h3 id="colorwrite-boolean" tabindex="-1"><a class="header-anchor" href="#colorwrite-boolean" aria-hidden="true">#</a> .colorWrite : Boolean</h3><p>是否渲染材质的颜色。 这可以与网格的renderOrder属性结合使用，以创建遮挡其他对象的不可见对象。默认值为true。</p><h3 id="defines-object" tabindex="-1"><a class="header-anchor" href="#defines-object" aria-hidden="true">#</a> .defines : Object</h3><p>注入shader的自定义对象。 以键值对形式的对象传递，{ MY_CUSTOM_DEFINE: &#39;&#39; , PI2: Math.PI * 2 }。 这些键值对在顶点和片元着色器中定义。默认值为undefined。</p><h3 id="depthfunc-integer" tabindex="-1"><a class="header-anchor" href="#depthfunc-integer" aria-hidden="true">#</a> .depthFunc : Integer</h3><p>使用何种深度函数。默认为LessEqualDepth。 深度模式所有可能的取值请查阅constants。</p><h3 id="depthtest-boolean" tabindex="-1"><a class="header-anchor" href="#depthtest-boolean" aria-hidden="true">#</a> .depthTest : Boolean</h3><p>是否在渲染此材质时启用深度测试。默认为 true。</p><h3 id="depthwrite-boolean" tabindex="-1"><a class="header-anchor" href="#depthwrite-boolean" aria-hidden="true">#</a> .depthWrite : Boolean</h3><p>渲染此材质是否对深度缓冲区有任何影响。默认为true。</p><p>在绘制2D叠加时，将多个事物分层在一起而不创建z-index时，禁用深度写入会很有用。</p><h3 id="forcesinglepass-boolean" tabindex="-1"><a class="header-anchor" href="#forcesinglepass-boolean" aria-hidden="true">#</a> .forceSinglePass : Boolean</h3><p>双面透明对象是否应该用单次传递渲染。默认为false。</p><h3 id="ismaterial-boolean" tabindex="-1"><a class="header-anchor" href="#ismaterial-boolean" aria-hidden="true">#</a> .isMaterial : Boolean</h3><p>检查这个对象是否为材质Material的只读标记.</p><h3 id="stencilwrite-boolean" tabindex="-1"><a class="header-anchor" href="#stencilwrite-boolean" aria-hidden="true">#</a> .stencilWrite : Boolean</h3><p>是否对模板缓冲执行模板操作，如果执行写入或者与模板缓冲进行比较，这个值需要设置为true。默认为false。</p><h3 id="stencilwritemask-integer" tabindex="-1"><a class="header-anchor" href="#stencilwritemask-integer" aria-hidden="true">#</a> .stencilWriteMask : Integer</h3><p>写入模板缓冲区时所用的位元遮罩，默认为0xFF。</p><h3 id="stencilfunc-integer" tabindex="-1"><a class="header-anchor" href="#stencilfunc-integer" aria-hidden="true">#</a> .stencilFunc : Integer</h3><p>使用模板比较时所用的方法，默认为AlwaysStencilFunc。在模板函数 constants 中查看可用的值</p><h3 id="stencilref-integer" tabindex="-1"><a class="header-anchor" href="#stencilref-integer" aria-hidden="true">#</a> .stencilRef : Integer</h3><p>在进行模板比较或者模板操作的时候所用的基准值，默认为0。</p><h3 id="stencilfuncmask-integer" tabindex="-1"><a class="header-anchor" href="#stencilfuncmask-integer" aria-hidden="true">#</a> .stencilFuncMask : Integer</h3><p>与模板缓冲进行比较时所使用的位元遮罩，默认为0xFF</p><h3 id="stencilfail-integer" tabindex="-1"><a class="header-anchor" href="#stencilfail-integer" aria-hidden="true">#</a> .stencilFail : Integer</h3><p>当比较函数没有通过的时候要执行的模板操作，默认为KeepStencilOp，在模板操作 constants 查看可用值。</p><h3 id="stencilzfail-integer" tabindex="-1"><a class="header-anchor" href="#stencilzfail-integer" aria-hidden="true">#</a> .stencilZFail : Integer</h3><p>当比较函数通过了但是深度检测没有通过的时候要执行的模板操作， 默认为KeepStencilOp，在模板操作 constants 查看可用值。</p><h3 id="stencilzpass-integer" tabindex="-1"><a class="header-anchor" href="#stencilzpass-integer" aria-hidden="true">#</a> .stencilZPass : Integer</h3><p>当比较函数和深度检测都通过时要执行的模板操作，默认为KeepStencilOp，在模板操作constants 中查看可用值。</p><h3 id="id-integer" tabindex="-1"><a class="header-anchor" href="#id-integer" aria-hidden="true">#</a> .id : Integer</h3><p>此材质实例的唯一编号。</p><h3 id="name-string" tabindex="-1"><a class="header-anchor" href="#name-string" aria-hidden="true">#</a> .name : String</h3><p>对象的可选名称（不必是唯一的）。默认值为空字符串。</p><h3 id="needsupdate-boolean" tabindex="-1"><a class="header-anchor" href="#needsupdate-boolean" aria-hidden="true">#</a> .needsUpdate : Boolean</h3><p>指定需要重新编译材质。</p><h3 id="opacity-float" tabindex="-1"><a class="header-anchor" href="#opacity-float" aria-hidden="true">#</a> .opacity : Float</h3><p>在0.0 - 1.0的范围内的浮点数，表明材质的透明度。值0.0表示完全透明，1.0表示完全不透明。<br> 如果材质的transparent属性未设置为true，则材质将保持完全不透明，此值仅影响其颜色。 默认值为1.0。</p><h3 id="polygonoffset-boolean" tabindex="-1"><a class="header-anchor" href="#polygonoffset-boolean" aria-hidden="true">#</a> .polygonOffset : Boolean</h3><p>是否使用多边形偏移。默认值为false。这对应于WebGL的GL_POLYGON_OFFSET_FILL功能。</p><h3 id="polygonoffsetfactor-integer" tabindex="-1"><a class="header-anchor" href="#polygonoffsetfactor-integer" aria-hidden="true">#</a> .polygonOffsetFactor : Integer</h3><p>设置多边形偏移系数。默认值为0。</p><h3 id="polygonoffsetunits-integer" tabindex="-1"><a class="header-anchor" href="#polygonoffsetunits-integer" aria-hidden="true">#</a> .polygonOffsetUnits : Integer</h3><p>设置多边形偏移单位。默认值为0。</p><h3 id="precision-string" tabindex="-1"><a class="header-anchor" href="#precision-string" aria-hidden="true">#</a> .precision : String</h3><p>重写此材质渲染器的默认精度。可以是&quot;highp&quot;, &quot;mediump&quot; 或 &quot;lowp&quot;。默认值为null。</p><h3 id="premultipliedalpha-boolean" tabindex="-1"><a class="header-anchor" href="#premultipliedalpha-boolean" aria-hidden="true">#</a> .premultipliedAlpha : Boolean</h3><p>是否预乘alpha（透明度）值。有关差异的示例，请参阅WebGL / Materials / Physical / Transmission。 默认值为false。</p><h3 id="dithering-boolean" tabindex="-1"><a class="header-anchor" href="#dithering-boolean" aria-hidden="true">#</a> .dithering : Boolean</h3><p>是否对颜色应用抖动以消除条带的外观。默认值为 false。</p><h3 id="shadowside-integer" tabindex="-1"><a class="header-anchor" href="#shadowside-integer" aria-hidden="true">#</a> .shadowSide : Integer</h3><p>定义投影的面。设置时，可以是THREE.FrontSide, THREE.BackSide, 或Materials。默认值为 null。<br> 如果为null， 则面投射阴影确定如下：</p><ul><li>THREE.FrontSide 背面</li><li>THREE.BackSide 前面</li><li>THREE.DoubleSide 双面</li></ul><h3 id="side-integer" tabindex="-1"><a class="header-anchor" href="#side-integer" aria-hidden="true">#</a> .side : Integer</h3><p>定义将要渲染哪一面 - 正面，背面或两者。 默认为THREE.FrontSide。其他选项有THREE.BackSide 和 THREE.DoubleSide。</p><h3 id="tonemapped-boolean" tabindex="-1"><a class="header-anchor" href="#tonemapped-boolean" aria-hidden="true">#</a> .toneMapped : Boolean</h3><p>定义这个材质是否会被渲染器的toneMapping设置所影响，默认为 true 。</p><h3 id="transparent-boolean" tabindex="-1"><a class="header-anchor" href="#transparent-boolean" aria-hidden="true">#</a> .transparent : Boolean</h3><p>定义此材质是否透明。这对渲染有影响，因为透明对象需要特殊处理，并在非透明对象之后渲染。<br> 设置为true时，通过设置材质的opacity属性来控制材质透明的程度。<br> 默认值为false。</p><h3 id="type-string" tabindex="-1"><a class="header-anchor" href="#type-string" aria-hidden="true">#</a> .type : String</h3><p>值是字符串&#39;Material&#39;。不应该被更改，并且可以用于在场景中查找此类型的所有对象。</p><h3 id="uuid-string" tabindex="-1"><a class="header-anchor" href="#uuid-string" aria-hidden="true">#</a> .uuid : String</h3><p>此材质实例的UUID，会自动分配，不应该被更改。</p><h3 id="version-integer" tabindex="-1"><a class="header-anchor" href="#version-integer" aria-hidden="true">#</a> .version : Integer</h3><p>开始为0，会记录 .needsUpdate : Boolean设置为true的次数。</p><h3 id="vertexcolors-boolean" tabindex="-1"><a class="header-anchor" href="#vertexcolors-boolean" aria-hidden="true">#</a> .vertexColors : Boolean</h3><p>是否使用顶点着色。默认值为false。</p><h3 id="visible-boolean" tabindex="-1"><a class="header-anchor" href="#visible-boolean" aria-hidden="true">#</a> .visible : Boolean</h3><p>此材质是否可见。默认为true。</p><h3 id="userdata-object" tabindex="-1"><a class="header-anchor" href="#userdata-object" aria-hidden="true">#</a> .userData : Object</h3><p>一个对象，可用于存储有关Material的自定义数据。它不应该包含对函数的引用，因为这些函数不会被克隆。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><h3 id="clone-material" tabindex="-1"><a class="header-anchor" href="#clone-material" aria-hidden="true">#</a> .clone ( ) : Material</h3><p>返回与此材质具有相同参数的新材质。</p><h3 id="copy-material-material-this" tabindex="-1"><a class="header-anchor" href="#copy-material-material-this" aria-hidden="true">#</a> .copy ( material : material ) : this</h3><p>将被传入材质中的参数复制到此材质中。</p><h3 id="dispose-undefined" tabindex="-1"><a class="header-anchor" href="#dispose-undefined" aria-hidden="true">#</a> .dispose () : undefined</h3><p>处理材质。材质的纹理不会被处理。需要通过Texture处理。</p><h3 id="onbeforecompile-shader-shader-renderer-webglrenderer-undefined" tabindex="-1"><a class="header-anchor" href="#onbeforecompile-shader-shader-renderer-webglrenderer-undefined" aria-hidden="true">#</a> .onBeforeCompile ( shader : Shader, renderer : WebGLRenderer ) : undefined</h3><p>在编译shader程序之前立即执行的可选回调。此函数使用shader源码作为参数。用于修改内置材质。</p><p>和其他属性不一样的是，这个回调在.clone()，.copy() 和 .toJSON() 中不支持。</p><h3 id="customprogramcachekey-string" tabindex="-1"><a class="header-anchor" href="#customprogramcachekey-string" aria-hidden="true">#</a> .customProgramCacheKey () : String</h3><p>当用到onBeforeCompile回调的时候，这个回调函数可以用来定义在onBeforeCompile中使用的配置项，这样three.js就可以根据这个回调返回的字符串来判定使用一个缓存的编译好的着色器代码还是根据需求重新编译一个新的着色器代码。</p><h3 id="setvalues-values-object-undefined" tabindex="-1"><a class="header-anchor" href="#setvalues-values-object-undefined" aria-hidden="true">#</a> .setValues ( values : Object ) : undefined</h3><p>values -- 具有参数的容器。 根据values设置属性。</p><h3 id="tojson-meta-object-object" tabindex="-1"><a class="header-anchor" href="#tojson-meta-object-object" aria-hidden="true">#</a> .toJSON ( meta : Object ) : Object</h3><p>meta -- 包含有元数据的对象，例如该对象的纹理或图片。 将material对象转换为 three.js JSON Object/Scene format（three.js JSON 物体/场景格式）。</p>',120),d=[t];function h(o,l){return a(),n("div",null,d)}const p=e(i,[["render",h],["__file","材质.html.vue"]]);export{p as default};
